INSERT INTO projects (title, slug, client, year, category, content, seo_description, cover_image, status) VALUES
('Chiến dịch Thời trang Mùa Hè', 'chin-dch-thi-trang-ma-h', 'Local Fashion Brand', '2023', 'E-Commerce / Social Media', '**Thách thức:**
Thị trường cạnh tranh khốc liệt vào mùa hè. Ngân sách hạn hẹp nhưng cần độ phủ lớn để đẩy mạnh doanh số trong vòng 2 tháng.

**Giải pháp:**
Sử dụng KOCs làm nòng cốt để tạo viral trên TikTok. Kết hợp với Performance Marketing để bám đuổi (retarget) và tối ưu hóa phễu trên Landing Page.

**Kết quả đạt được:**
- Tăng 150% doanh thu trực tuyến so với cùng kỳ năm ngoái.
- ROE đạt mức 3.5x.
- +50,000 lượt theo dõi mới trên Instagram và TikTok.', 'Một chiến dịch ra mắt bộ sưu tập mùa hè tập trung vào khách hàng Gen Z. Tối ưu hóa chuyển đổi qua các nền tảng Social Media như TikTok và Instagram.', 'https://images.unsplash.com/photo-1441984904996-e0b6ba687e04?auto=format&fit=crop&q=80&w=1200', 'completed'),
('Tăng trưởng Ứng dụng Finance', 'tng-trng-ng-dng-finance', 'Startup Fintech (Series A)', '2023', 'Fintech / Performance Marketing', '**Thách thức:**
Chi phí để có được người dùng mới (CAC) trong ngành Fintech rất cao. Cần tìm ra các kênh và thông điệp tối ưu hóa chi phí.

**Giải pháp:**
A/B Testing liên tục hàng chục mẫu quảng cáo và thông điệp khác nhau. Tối ưu hóa hành trình đăng ký trên ứng dụng để giảm tỷ lệ bỏ cuộc ở bước xác thực danh tính.

**Kết quả đạt được:**
- Giảm 40% Chi phí trên mỗi lượt cài đặt (CPI).
- Tỷ lệ hoàn thành KYC tăng từ 25% lên 45%.
- Góp phần mang về 100,000 người dùng hàng tháng (MAU).', 'Tối ưu hóa lượt tải và đăng ký tài khoản (KYC) cho một ứng dụng công nghệ tài chính mới nổi tại Việt Nam.', 'https://images.unsplash.com/photo-1560472354-b33ff0c44a43?auto=format&fit=crop&q=80&w=1200', 'completed'),
('Ra mắt Nền tảng Đám mây', 'ra-mt-nn-tng-m-my', 'Enterprise Tech Company', '2024', 'SaaS / B2B Strategy', '**Thách thức:**
Sản phẩm kỹ thuật phức tạp khó giải thích. Chu kỳ bán hàng dài (3-6 tháng) đòi hỏi duy trì liên lạc và nội dung chất lượng cao liên tục.

**Giải pháp:**
Xây dựng chiến lược Inbound Marketing bằng các Whitepapers và Case Studies chuyên sâu. Tổ chức chuỗi Webinars để thu hút và nuôi dưỡng leads.

**Kết quả đạt được:**
- Tạo ra 500+ Qualified Leads (SQL) trong Quý 1.
- Tăng tỷ lệ chuyển đổi từ MQL sang SQL lên 20%.
- Rút ngắn 15% thời gian chốt sale.', 'Hoạch định chiến lược go-to-market cho sản phẩm B2B nhắm đến các khách hàng doanh nghiệp vừa và lớn.', 'https://images.unsplash.com/photo-1550751827-4bd374c3f58b?auto=format&fit=crop&q=80&w=1200', 'completed'),
('Tạp chí Kiến trúc Toàn cầu', 'tp-ch-kin-trc-ton-cu', 'Architecture Magazine', '2024', 'Editorial / Content Marketing', '**Thách thức:**
Mất dần độc giả trẻ. Phiên bản in không còn thu hút do sự bùng nổ của nội dung số và các nền tảng mạng xã hội.

**Giải pháp:**
Chuyển dịch sang mô hình ''Digital-First''. Thiết kế lại cấu trúc SEO, khai thác nội dung video ngắn (Reels, Shorts) về không gian sống.

**Kết quả đạt được:**
- Lượt truy cập Organic Search tăng 200%.
- Tăng 30% lượng người đăng ký đọc Newsletter hàng tuần.
- Xây dựng thành công cộng đồng hơn 100,000 thành viên yêu kiến trúc.', 'Tái định vị và đẩy mạnh phát hành nội dung số cho một tạp chí kiến trúc danh tiếng.', 'https://images.unsplash.com/photo-1600585154340-be6161a56a0c?auto=format&fit=crop&q=80&w=1200', 'completed'),
('Hệ thống AI tự động đăng bài Facebook & Instagram', 'h-thng-ai-t-ng-ng-bi-facebook--instagram', 'Multi-brand Social Automation System', '2024', 'Automation / AI Content / Social Media', '**Thách thức:**
Doanh nghiệp quản lý nhiều thương hiệu thường tốn rất nhiều thời gian để lên ý tưởng, viết caption, chuẩn bị hình ảnh, theo dõi lịch đăng và đăng thủ công trên từng Fanpage. Khi số lượng Page tăng lên vài chục hoặc hàng trăm, việc kiểm soát nội dung, lịch đăng và trạng thái xuất bản trở nên rất dễ sai sót.

**Giải pháp:**
Thiết kế hệ thống vận hành qua Google Sheet làm trung tâm điều phối. Người dùng chỉ cần nhập thông tin thương hiệu, chủ đề, ngày giờ đăng, tệp khách hàng và kênh cần xuất bản. AI sẽ tự động gợi ý ý tưởng, viết caption theo giọng thương hiệu, chuẩn bị nội dung cho Facebook/Instagram và gửi qua quy trình đăng tự động bằng Apps Script kết hợp API Meta. Hệ thống có thể mở rộng để quản lý lên đến 100 Fanpage/Instagram Business Account, theo dõi trạng thái từng bài, ghi log lỗi và hỗ trợ chỉnh sửa nội dung trước khi đăng.

**Kết quả đạt được:**
- Tự động hóa quy trình từ lên ý tưởng, viết nội dung đến đăng bài đa kênh.
- Quản lý tập trung lên đến 100 Fanpage/Instagram ngay trên Google Sheet.
- Tiết kiệm 70-90% thời gian vận hành nội dung social media hằng tuần.
- Theo dõi lịch đăng, trạng thái xuất bản và lỗi API theo thời gian thực.', 'Xây dựng hệ thống tự động hóa nội dung cho doanh nghiệp: cấu hình kế hoạch đăng bài ngay trên Google Sheet, AI tự viết nội dung, tạo lịch và tự động đăng lên Fanpage Facebook và Instagram.', 'https://images.unsplash.com/photo-1611162617213-7d7a39e9b1d7?auto=format&fit=crop&q=80&w=1200', 'completed'),
('Chatbot AI chăm sóc khách hàng đa kênh', 'chatbot-ai-chm-sc-khch-hng-a-knh', 'Omnichannel AI Customer Care Platform', '2024', 'AI Chatbot / Customer Service / Omnichannel Automation', '**Thách thức:**
Đội ngũ chăm sóc khách hàng thường bị quá tải khi tin nhắn đến từ nhiều nền tảng khác nhau. Khách hàng cần phản hồi nhanh 24/7, trong khi nhân sự khó theo kịp số lượng hội thoại, lịch sử tư vấn bị phân tán và lead nóng dễ bị bỏ sót.

**Giải pháp:**
Xây dựng Chatbot AI đa kênh kết nối Website, Facebook Messenger, Instagram Direct, Zalo OA, WhatsApp và CRM nội bộ. AI có khả năng hiểu câu hỏi tự nhiên, tư vấn sản phẩm/dịch vụ theo kịch bản thương hiệu, thu thập thông tin khách hàng, chấm điểm lead, chuyển tiếp cho nhân viên khi cần và lưu toàn bộ lịch sử hội thoại về một trung tâm quản trị. Hệ thống có thể tích hợp kho dữ liệu FAQ, bảng giá, lịch hẹn, đơn hàng và automation workflow để tự động nhắc lịch, gửi báo giá, chăm sóc sau mua và tái kích hoạt khách hàng cũ.

**Kết quả đạt được:**
- Tự động phản hồi khách hàng 24/7 trên nhiều kênh cùng lúc.
- Tập trung toàn bộ hội thoại Facebook, Instagram, Zalo, Website và WhatsApp về một hệ thống.
- Giảm tải 60-80% khối lượng câu hỏi lặp lại cho đội ngũ CSKH.
- Tự động phân loại lead nóng, ghi nhận nhu cầu và chuyển nhân viên phụ trách đúng thời điểm.
- Chuẩn hóa trải nghiệm tư vấn, chăm sóc trước và sau bán hàng theo giọng thương hiệu.', 'Triển khai hệ thống Chatbot AI tự động tư vấn, chăm sóc khách hàng và phân loại nhu cầu trên nhiều kênh như Website, Facebook Messenger, Instagram, Zalo OA và WhatsApp.', 'https://images.unsplash.com/photo-1531746790731-6c087fecd65a?auto=format&fit=crop&q=80&w=1200', 'completed'),
('Hệ thống quản lý vận hành khách sạn thông minh', 'h-thng-qun-l-vn-hnh-khch-sn-thng-minh', 'Boutique Hotel & Resort Chain', '2024', 'PMS / Hotel Automation / AI Optimization', '**Thách thức:**
Các khách sạn truyền thống gặp khó khăn trong việc đồng bộ hóa dữ liệu giữa các sàn OTA (Agoda, Booking, v.v.), quy trình check-in/check-out thủ công chậm chạp, và khó khăn trong việc dự báo nhu cầu để điều chỉnh giá phòng linh hoạt.

**Giải pháp:**
Xây dựng nền tảng quản lý tập trung kết nối Channel Manager (đồng bộ kho phòng đa kênh), tích hợp hệ thống tự động hóa task cho nhân viên buồng phòng qua Mobile App. Đặc biệt, tích hợp AI Engine để phân tích dữ liệu lịch sử và xu hướng thị trường nhằm gợi ý giá phòng tối ưu theo thời gian thực (Dynamic Pricing). Hệ thống cũng bao gồm giải pháp Smart Check-in tự động gửi mã phòng/QR cho khách qua Zalo/Email, giảm thiểu tiếp xúc và thời gian chờ đợi tại sảnh.

**Kết quả đạt được:**
- Tự động hóa 90% quy trình đồng bộ kho phòng và giá bán trên các sàn OTA.
- Tăng 25% doanh thu nhờ chiến lược giá linh hoạt (Dynamic Pricing) do AI gợi ý.
- Giảm 40% thời gian chờ đợi check-in của khách hàng thông qua hệ thống tự động.
- Tối ưu hóa hiệu suất làm việc của đội ngũ buồng phòng nhờ hệ thống quản lý task thông minh trên Mobile.
- Báo cáo tài chính và hiệu suất vận hành được cập nhật realtime chính xác 100%.', 'Phát triển hệ thống quản lý khách sạn (Property Management System - PMS) toàn diện, tích hợp AI để tự động hóa quy trình đặt phòng, quản lý buồng phòng, và tối ưu hóa doanh thu.', 'https://images.unsplash.com/photo-1566073771259-6a8506099945?auto=format&fit=crop&q=80&w=1200', 'completed'),
('Hệ thống tự động hóa xử lý hóa đơn (AI OCR)', 'h-thng-t-ng-ha-x-l-ha-n-ai-ocr', 'Retail & Distribution Company', '2024', 'AI OCR / Finance Automation / Workflow Optimization', '**Thách thức:**
Bộ phận kế toán phải xử lý hàng trăm hóa đơn mỗi ngày từ email của nhà cung cấp. Việc nhập liệu thủ công tốn nhiều thời gian, dễ xảy ra sai sót về số liệu và chậm trễ trong việc tổng hợp báo cáo chi phí.

**Giải pháp:**
Phát triển quy trình tự động hóa sử dụng Google Apps Script kết hợp với AI OCR (như Google Cloud Vision hoặc OpenAI GPT-4o) để tự động quét các email mới, tải tệp đính kèm (PDF, hình ảnh), trích xuất các thông tin quan trọng như: số hóa đơn, ngày phát hành, mã số thuế, danh sách sản phẩm, đơn giá và tổng tiền. Toàn bộ dữ liệu sau đó được chuẩn hóa và tự động ghi vào Google Sheets theo thời gian thực, đồng thời lưu trữ tệp gốc vào Google Drive để đối chiếu.

**Kết quả đạt được:**
- Tự động hóa 100% quy trình thu thập và phân loại hóa đơn từ Email.
- Giảm 95% thời gian nhập liệu thủ công cho bộ phận kế toán.
- Độ chính xác trích xuất dữ liệu đạt trên 98% nhờ công nghệ AI OCR hiện đại.
- Dữ liệu chi phí được cập nhật realtime, giúp quản lý theo dõi ngân sách tức thì.
- Hệ thống tự động cảnh báo khi có hóa đơn trùng lặp hoặc sai lệch thông tin.', 'Xây dựng hệ thống tự động quét email, trích xuất dữ liệu hóa đơn bằng công nghệ AI OCR và đồng bộ dữ liệu trực tiếp về Google Sheets hoặc ERP doanh nghiệp.', 'https://images.unsplash.com/photo-1554224155-6726b3ff858f?auto=format&fit=crop&q=80&w=1200', 'completed'),
('Hệ thống quản lý đặt bàn cho nhà hàng Pháp', 'h-thng-qun-l-t-bn-cho-nh-hng-php', 'French Fine Dining Restaurant', '2024', 'Restaurant Tech / Reservation System / AI Operations', '**Thách thức:**
Nhà hàng cao cấp thường phải xử lý nhiều nguồn đặt bàn từ điện thoại, Facebook, Website, Google Business và khách quen. Việc ghi nhận thủ công dễ gây trùng lịch, nhầm số lượng khách, bỏ sót yêu cầu đặc biệt và khó kiểm soát tình trạng bàn theo thời gian thực.

**Giải pháp:**
Thiết kế hệ thống đặt bàn tập trung với giao diện quản trị trực quan cho lễ tân và quản lý. Khách có thể đặt bàn online, chọn ngày giờ, số lượng khách, ghi chú dị ứng/thực đơn đặc biệt và nhận xác nhận tự động qua Email/Zalo. Hệ thống tích hợp sơ đồ bàn realtime, cảnh báo trùng booking, tự động nhắc lịch trước giờ dùng bữa và đồng bộ dữ liệu khách hàng vào CRM. AI hỗ trợ phân tích lịch sử đặt bàn, dự đoán khung giờ cao điểm, gợi ý phân bổ bàn tối ưu và tạo nội dung chăm sóc khách hàng sau bữa ăn.

**Kết quả đạt được:**
- Quản lý tập trung toàn bộ đặt bàn từ Website, Facebook, Google Business và hotline.
- Giảm 80% lỗi trùng lịch, nhầm bàn hoặc bỏ sót yêu cầu đặc biệt của khách.
- Tự động gửi xác nhận, nhắc lịch và chăm sóc sau bữa ăn qua Email/Zalo.
- Tối ưu công suất bàn theo thời gian thực nhờ sơ đồ bàn và cảnh báo thông minh.
- Tăng trải nghiệm khách hàng cao cấp đúng tiêu chuẩn nhà hàng Pháp fine dining.', 'Xây dựng hệ thống quản lý đặt bàn toàn diện cho nhà hàng Pháp, tối ưu quy trình nhận booking, sắp xếp bàn, nhắc lịch khách hàng và điều phối vận hành nội bộ.', 'https://images.unsplash.com/photo-1414235077428-338989a2e8c0?auto=format&fit=crop&q=80&w=1200', 'completed'),
('Thiết kế & xây dựng Website doanh nghiệp cao cấp', 'thit-k--xy-dng-website-doanh-nghip-cao-cp', 'Premium Business Website', '2024', 'Web Development / UI UX / SEO Optimization', '**Thách thức:**
Nhiều doanh nghiệp có website cũ chậm, giao diện thiếu chuyên nghiệp, không tối ưu mobile và chưa thể hiện được định vị thương hiệu. Điều này làm giảm niềm tin khách hàng, giảm tỷ lệ chuyển đổi và khiến chi phí quảng cáo không tạo ra hiệu quả tương xứng.

**Giải pháp:**
Xây dựng website theo hướng premium brand experience: giao diện responsive trên mọi thiết bị, bố cục chuyển đổi rõ ràng, nội dung chuẩn SEO, tốc độ tải nhanh và dễ dàng quản trị. Hệ thống có thể tích hợp form thu lead, chatbot AI, blog, landing page chiến dịch, Google Analytics, Meta Pixel, CRM, email automation và các API thanh toán hoặc đặt lịch tùy theo mô hình kinh doanh.

**Kết quả đạt được:**
- Giao diện website cao cấp, chuyên nghiệp và đồng bộ nhận diện thương hiệu.
- Tối ưu trải nghiệm mobile, tốc độ tải trang và cấu trúc SEO nền tảng.
- Tăng tỷ lệ chuyển đổi từ quảng cáo nhờ landing page và CTA được thiết kế rõ ràng.
- Dễ dàng mở rộng thành hệ thống bán hàng, booking, blog hoặc cổng quản trị nội dung.
- Tích hợp tracking, chatbot AI, form lead và automation để hỗ trợ tăng trưởng dài hạn.', 'Thiết kế và phát triển website doanh nghiệp hiện đại, tối ưu tốc độ, chuẩn SEO, giao diện cao cấp và có khả năng mở rộng thành hệ thống bán hàng, landing page hoặc nền tảng quản trị nội dung.', 'https://images.unsplash.com/photo-1547658719-da2b51169166?auto=format&fit=crop&q=80&w=1200', 'completed');
